sql:
SELECT meter_id, meter_type, meter_model
FROM smart_meters
WHERE meter_model LIKE '%100A%';

SELECT name 
FROM customers 
WHERE peak_demand_kw = (SELECT MAX(peak_demand_kw) FROM customers);

SELECT request_type, COUNT(*) 
FROM customer_requests 
GROUP BY request_type;

SELECT customer_id, location
FROM power_consumption_data
WHERE (p1_kw > 10 OR p2_kw > 10 OR p3_kw > 10) AND location = 'New York';

SELECT COUNT(*) AS Total_Outages
FROM power_outages
WHERE affected_customers > 0;

external_knowledge:
- "storm cloud" metaphorically represents the outage type;
- "casting its shadow over us" refers to the downtime caused by the outage;
- The duration is calculated in minutes for each event.

sql:
SELECT customers.name, smart_meters.meter_model
FROM customers
INNER JOIN smart_meters ON customers.customer_id = smart_meters.customer_id;

external_knowledge:
- 'Households' refers to 'residential customers'.;
- 'Power usage recorded throughout the entire year of 2022' refers to the timestamp in the power consumption data between '2022-01-01' and '2022-12-31'.;
- 'Active power readings at three points' refers to the 'p1_kw', 'p2_kw', and 'p3_kw' measurements.;

sql:
SELECT COUNT(DISTINCT customer_id)
FROM smart_meters
WHERE meter_type = 'single-phase';

SELECT sm.meter_id, id.device_id, sm.customer_id, sm.meter_serial_number, id.device_serial_number
FROM smart_meters sm
INNER JOIN iot_devices id ON sm.customer_id = id.customer_id;

SELECT outage_type, outage_cause, outage_resolution
FROM power_outages
WHERE outage_id = 1;

SELECT COUNT(DISTINCT customer_id) AS total_customers
FROM customer_requests
WHERE request_type = 'meter reading' AND request_time >= date('now', '-1 month');
